A debounce function delays invoking a callback until a specified wait time has passed without any new calls.

```javascript
function debounce(fn, wait) {
  let t;
  return function (...args) {
    clearTimeout(t);
    t = setTimeout(() => fn.apply(this, args), wait);
  };
}

// Example usage:
window.addEventListener('resize', debounce(() => {
  console.log('Resize finished');
}, 300));
```
